interface User {
  id: number;
  username: string;
  email: string;
}

// We explicitly demand the variable matches one of the User keys
type UserKey = keyof User;

let validKey: UserKey = "email"; // Works perfectly
let invalidKey: UserKey = "password"; // Error: 'password' is not in User

let userEmail: string | null = "alice@test.com";

// TS natively complains because userEmail might be exactly null here
// console.log(userEmail.toUpperCase()); 

// Appending ! firmly asserts it is definitely a valid string
console.log(userEmail!.toUpperCase());
